"""
TDD Stage: affine_transform
Add gamma (scale) and beta (bias) support with ROW broadcast.
Reader loads gamma/beta tiles at startup.
Compute applies mul(ROW) and add(ROW) phases.
"""

import pytest
import torch
import ttnn


from .layer_norm_rm import layer_norm_rm


def pytorch_reference(x, gamma_1d, beta_1d):
    """PyTorch reference for this stage."""
    return torch.nn.functional.layer_norm(
        x.float(),
        [x.shape[-1]],
        weight=gamma_1d.squeeze().float(),
        bias=beta_1d.squeeze().float(),
        eps=1e-5,
    ).to(torch.bfloat16)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
    ],
)
def test_affine_transform(device, shape):
    """Verify layer_norm_rm with gamma and beta affine transform."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    gamma_1d = torch.randn(1, 1, 1, shape[-1], dtype=torch.bfloat16)
    beta_1d = torch.randn(1, 1, 1, shape[-1], dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input, gamma_1d, beta_1d)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    gamma_tt = ttnn.from_torch(gamma_1d, dtype=ttnn.bfloat16, layout=ttnn.ROW_MAJOR_LAYOUT, device=device)
    beta_tt = ttnn.from_torch(beta_1d, dtype=ttnn.bfloat16, layout=ttnn.ROW_MAJOR_LAYOUT, device=device)

    ttnn_output = layer_norm_rm(ttnn_input, gamma=gamma_tt, beta=beta_tt)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
